package python

// validate.go — emits _validators.py when EmitOptions.Validate is true.
//
// The generated file contains zero-dependency runtime validators:
//   - VeldContractError   — raised on output shape violation  (HTTP 500)
//   - VeldValidationError — raised on input parsing failure   (HTTP 400)
//   - assert_x()          — asserts output shape matches contract model
//   - assert_x_list()     — asserts output is a list of model (when needed)
//   - parse_x()           — parses + validates request input model
//
// Pure Python stdlib — no Pydantic, no marshmallow, no external deps.

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
)

// emitValidators writes generated/_validators.py with zero-dep runtime validators.
func (e *PythonEmitter) emitValidators(a ast.AST, outDir string) error {
	var sb strings.Builder

	sb.WriteString("# AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("# Runtime contract validators \u2014 zero external dependencies\n")
	sb.WriteString("#\n")
	sb.WriteString("# assert_x()      \u2014 output shape guard     \u2192 raises VeldContractError   (HTTP 500)\n")
	sb.WriteString("# assert_x_list() \u2014 output list guard      \u2192 raises VeldContractError   (HTTP 500)\n")
	sb.WriteString("# parse_x()       \u2014 input parser/validator \u2192 raises VeldValidationError (HTTP 400)\n")
	sb.WriteString("from __future__ import annotations\n")
	sb.WriteString("from typing import Any\n\n\n")

	// ── Error classes ─────────────────────────────────────────────────────────
	sb.WriteString(pyErrorClasses)
	sb.WriteString("\n")

	// ── Gather metadata ───────────────────────────────────────────────────────
	byName := pyModelsByName(a.Models)
	enumNames := pyEnumSet(a.Enums)
	listOutputModels := pyCollectListOutputModels(a)
	inputModels := pyCollectInputModels(a)

	// ── Emit assert_x / assert_x_list — topologically sorted ─────────────────
	sorted := pyTopoSortModels(a.Models)
	for _, model := range sorted {
		writePyAssertFunc(&sb, model, byName, enumNames)
		sb.WriteString("\n")
		if listOutputModels[model.Name] {
			writePyAssertListFunc(&sb, model)
			sb.WriteString("\n")
		}
	}

	// ── Emit parse_x — only for models used as action inputs ─────────────────
	for _, model := range sorted {
		if inputModels[model.Name] {
			writePyParseFunc(&sb, model, byName, enumNames)
			sb.WriteString("\n")
		}
	}

	return os.WriteFile(filepath.Join(outDir, "_validators.py"), []byte(sb.String()), 0644)
}

// ── Template: error classes ───────────────────────────────────────────────────

const pyErrorClasses = `class VeldContractError(Exception):
    """Raised when a service returns a response that violates the contract shape (HTTP 500)."""

    status: int = 500

    def __init__(self, field: str, expected: str, actual: Any = None) -> None:
        got = type(actual).__name__ if actual is not None else "None"
        super().__init__(f"Contract violation \u2014 {field}: expected {expected}, got {got}")
        self.field = field
        self.expected = expected


class VeldValidationError(Exception):
    """Raised when request input fails shape validation (HTTP 400)."""

    status: int = 400
    code: str = "VALIDATION_ERROR"

    def __init__(self, errors: list) -> None:
        super().__init__("Validation failed: " + "; ".join(errors))
        self.errors = errors

`

// ── assert_x ──────────────────────────────────────────────────────────────────

func writePyAssertFunc(sb *strings.Builder, model ast.Model, byName map[string]ast.Model, enumNames map[string]bool) {
	fnName := "assert_" + emitter.ToSnakeCase(model.Name)
	sb.WriteString(fmt.Sprintf("def %s(data: Any, path: str = %q) -> None:\n", fnName, model.Name))
	sb.WriteString(fmt.Sprintf("    \"\"\"Assert data matches the %s contract shape. Raises VeldContractError (\u2192 500) on mismatch.\"\"\"\n", model.Name))
	sb.WriteString("    if not isinstance(data, dict):\n")
	sb.WriteString(fmt.Sprintf("        raise VeldContractError(path, \"dict\", data)\n"))

	// Delegate parent field validation to the parent assert function.
	if model.Extends != "" {
		sb.WriteString(fmt.Sprintf("    assert_%s(data, path)\n", emitter.ToSnakeCase(model.Extends)))
	}

	for _, field := range model.Fields {
		writePyAssertField(sb, field, byName, enumNames)
	}

	sb.WriteString("\n")
}

// writePyAssertField emits the per-field check inside an assert_x function.
func writePyAssertField(sb *strings.Builder, field ast.Field, byName map[string]ast.Model, enumNames map[string]bool) {
	key := fmt.Sprintf("data.get(%q)", field.Name)
	pathExpr := fmt.Sprintf("f\"{path}.%s\"", field.Name)

	if field.Optional {
		writePyAssertFieldOptional(sb, field, key, pathExpr, byName, enumNames)
	} else {
		writePyAssertFieldRequired(sb, field, key, pathExpr, byName, enumNames)
	}
}

func writePyAssertFieldRequired(sb *strings.Builder, field ast.Field, key, pathExpr string, byName map[string]ast.Model, enumNames map[string]bool) {
	switch {
	case field.IsArray:
		sb.WriteString(fmt.Sprintf("    if not isinstance(%s, list):\n", key))
		sb.WriteString(fmt.Sprintf("        raise VeldContractError(%s, \"list\", %s)\n", pathExpr, key))
		if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("    for _i, _item in enumerate(%s):\n", key))
			sb.WriteString(fmt.Sprintf("        assert_%s(_item, f\"{path}.%s[{_i}]\")\n", emitter.ToSnakeCase(field.Type), field.Name))
		}

	case field.IsMap:
		sb.WriteString(fmt.Sprintf("    if not isinstance(%s, dict):\n", key))
		sb.WriteString(fmt.Sprintf("        raise VeldContractError(%s, \"dict\", %s)\n", pathExpr, key))

	default:
		if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("    assert_%s(%s, %s)\n", emitter.ToSnakeCase(field.Type), key, pathExpr))
		} else {
			expected, check := pyScalarCheck(field.Type, key)
			sb.WriteString(fmt.Sprintf("    if not %s:\n", check))
			sb.WriteString(fmt.Sprintf("        raise VeldContractError(%s, %q, %s)\n", pathExpr, expected, key))
		}
	}
}

func writePyAssertFieldOptional(sb *strings.Builder, field ast.Field, key, pathExpr string, byName map[string]ast.Model, enumNames map[string]bool) {
	switch {
	case field.IsArray:
		sb.WriteString(fmt.Sprintf("    if %s is not None and not isinstance(%s, list):\n", key, key))
		sb.WriteString(fmt.Sprintf("        raise VeldContractError(%s, \"list | None\", %s)\n", pathExpr, key))
		if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("    if isinstance(%s, list):\n", key))
			sb.WriteString(fmt.Sprintf("        for _i, _item in enumerate(%s):\n", key))
			sb.WriteString(fmt.Sprintf("            assert_%s(_item, f\"{path}.%s[{_i}]\")\n", emitter.ToSnakeCase(field.Type), field.Name))
		}

	case field.IsMap:
		sb.WriteString(fmt.Sprintf("    if %s is not None and not isinstance(%s, dict):\n", key, key))
		sb.WriteString(fmt.Sprintf("        raise VeldContractError(%s, \"dict | None\", %s)\n", pathExpr, key))

	default:
		if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("    if %s is not None:\n", key))
			sb.WriteString(fmt.Sprintf("        assert_%s(%s, %s)\n", emitter.ToSnakeCase(field.Type), key, pathExpr))
		} else if !enumNames[field.Type] {
			// Enums are string literals — skip runtime check (typing handles it).
			expected, check := pyScalarCheck(field.Type, key)
			sb.WriteString(fmt.Sprintf("    if %s is not None and not %s:\n", key, check))
			sb.WriteString(fmt.Sprintf("        raise VeldContractError(%s, \"%s | None\", %s)\n", pathExpr, expected, key))
		}
	}
}

// ── assert_x_list ─────────────────────────────────────────────────────────────

func writePyAssertListFunc(sb *strings.Builder, model ast.Model) {
	fnName := "assert_" + emitter.ToSnakeCase(model.Name) + "_list"
	sb.WriteString(fmt.Sprintf("def %s(data: Any, path: str = %q) -> None:\n", fnName, model.Name+"[]"))
	sb.WriteString(fmt.Sprintf("    \"\"\"Assert data is a list of %s. Raises VeldContractError (\u2192 500) on mismatch.\"\"\"\n", model.Name))
	sb.WriteString("    if not isinstance(data, list):\n")
	sb.WriteString("        raise VeldContractError(path, \"list\", data)\n")
	sb.WriteString("    for i, item in enumerate(data):\n")
	sb.WriteString(fmt.Sprintf("        assert_%s(item, f\"{path}[{i}]\")\n", emitter.ToSnakeCase(model.Name)))
	sb.WriteString("\n")
}

// ── parse_x ───────────────────────────────────────────────────────────────────

// writePyParseFunc generates parse_x() which collects all validation errors
// before raising, giving developers a complete picture of what's wrong.
func writePyParseFunc(sb *strings.Builder, model ast.Model, byName map[string]ast.Model, enumNames map[string]bool) {
	fnName := "parse_" + emitter.ToSnakeCase(model.Name)
	sb.WriteString(fmt.Sprintf("def %s(data: Any) -> dict:\n", fnName))
	sb.WriteString(fmt.Sprintf("    \"\"\"Parse and validate request input as %s. Raises VeldValidationError (\u2192 400) on failure.\"\"\"\n", model.Name))
	sb.WriteString("    if not isinstance(data, dict):\n")
	sb.WriteString("        raise VeldValidationError([\"request body must be a JSON object\"])\n")
	sb.WriteString("    _errors: list = []\n")

	// Include parent fields so the full input model is validated.
	allFields := pyCollectAllFields(model, byName)
	for _, field := range allFields {
		writePyParseField(sb, field, byName, enumNames)
	}

	sb.WriteString("    if _errors:\n")
	sb.WriteString("        raise VeldValidationError(_errors)\n")
	sb.WriteString("    return data\n")
	sb.WriteString("\n")
}

// writePyParseField emits the per-field validation inside a parse_x function.
func writePyParseField(sb *strings.Builder, field ast.Field, byName map[string]ast.Model, enumNames map[string]bool) {
	key := fmt.Sprintf("data.get(%q)", field.Name)

	if field.Optional {
		if field.IsArray {
			sb.WriteString(fmt.Sprintf("    if %s is not None and not isinstance(%s, list):\n", key, key))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": expected list"))
		} else if field.IsMap {
			sb.WriteString(fmt.Sprintf("    if %s is not None and not isinstance(%s, dict):\n", key, key))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": expected dict (map)"))
		} else if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("    if %s is not None and not isinstance(%s, dict):\n", key, key))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": expected dict"))
		} else if !enumNames[field.Type] {
			expected, check := pyScalarCheck(field.Type, key)
			sb.WriteString(fmt.Sprintf("    if %s is not None and not %s:\n", key, check))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": expected "+expected))
		}
	} else {
		if field.IsArray {
			sb.WriteString(fmt.Sprintf("    if not isinstance(%s, list):\n", key))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": required list"))
		} else if field.IsMap {
			sb.WriteString(fmt.Sprintf("    if not isinstance(%s, dict):\n", key))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": required dict (map)"))
		} else if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("    if not isinstance(%s, dict):\n", key))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": required dict"))
		} else if enumNames[field.Type] {
			sb.WriteString(fmt.Sprintf("    if not isinstance(%s, str):\n", key))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": required str (enum "+field.Type+")"))
		} else {
			expected, check := pyScalarCheck(field.Type, key)
			sb.WriteString(fmt.Sprintf("    if not %s:\n", check))
			sb.WriteString(fmt.Sprintf("        _errors.append(%q)\n", field.Name+": required "+expected))
		}
	}
}

// ── Shared helpers ────────────────────────────────────────────────────────────

func pyTopoSortModels(models []ast.Model) []ast.Model {
	byName := pyModelsByName(models)
	visited := make(map[string]bool, len(models))
	result := make([]ast.Model, 0, len(models))

	var visit func(name string)
	visit = func(name string) {
		if visited[name] {
			return
		}
		visited[name] = true
		if m, ok := byName[name]; ok && m.Extends != "" {
			visit(m.Extends)
		}
		if m, ok := byName[name]; ok {
			result = append(result, m)
		}
	}
	for _, m := range models {
		visit(m.Name)
	}
	return result
}

func pyModelsByName(models []ast.Model) map[string]ast.Model {
	m := make(map[string]ast.Model, len(models))
	for _, model := range models {
		m[model.Name] = model
	}
	return m
}

func pyEnumSet(enums []ast.Enum) map[string]bool {
	s := make(map[string]bool, len(enums))
	for _, e := range enums {
		s[e.Name] = true
	}
	return s
}

func pyCollectListOutputModels(a ast.AST) map[string]bool {
	result := make(map[string]bool)
	for _, mod := range a.Modules {
		for _, act := range mod.Actions {
			if act.Output != "" && act.OutputArray {
				result[act.Output] = true
			}
		}
	}
	return result
}

func pyCollectInputModels(a ast.AST) map[string]bool {
	result := make(map[string]bool)
	for _, mod := range a.Modules {
		for _, act := range mod.Actions {
			if act.Input != "" {
				result[act.Input] = true
			}
		}
	}
	return result
}

func pyCollectAllFields(model ast.Model, byName map[string]ast.Model) []ast.Field {
	var fields []ast.Field
	if model.Extends != "" {
		if parent, ok := byName[model.Extends]; ok {
			fields = append(fields, pyCollectAllFields(parent, byName)...)
		}
	}
	return append(fields, model.Fields...)
}

// pyScalarCheck returns (expectedLabel, isinstanceExpr) for a Veld scalar type.
// Python quirk: bool is a subclass of int, so int checks exclude bool explicitly.
func pyScalarCheck(veldType, varExpr string) (expected, check string) {
	switch veldType {
	case "string", "date", "datetime", "uuid", "time":
		return "str", fmt.Sprintf("isinstance(%s, str)", varExpr)
	case "bytes":
		return "bytes", fmt.Sprintf("isinstance(%s, bytes)", varExpr)
	case "int", "long":
		return "int", fmt.Sprintf("isinstance(%s, int) and not isinstance(%s, bool)", varExpr, varExpr)
	case "float":
		return "float", fmt.Sprintf("isinstance(%s, (int, float)) and not isinstance(%s, bool)", varExpr, varExpr)
	case "decimal":
		return "Decimal or str", fmt.Sprintf("isinstance(%s, (str, Decimal))", varExpr)
	case "bool":
		return "bool", fmt.Sprintf("isinstance(%s, bool)", varExpr)
	default:
		return "str", fmt.Sprintf("isinstance(%s, str)", varExpr)
	}
}

// buildPyValidatorImports collects the validator function names needed by a module's routes.
func buildPyValidatorImports(mod ast.Module) []string {
	seen := make(map[string]bool)
	for _, act := range mod.Actions {
		if act.Method == "WS" {
			continue
		}
		if act.Input != "" {
			seen["parse_"+emitter.ToSnakeCase(act.Input)] = true
		}
		if act.Output != "" && !(act.Method == "DELETE" && act.Output == "") {
			if act.OutputArray {
				seen["assert_"+emitter.ToSnakeCase(act.Output)+"_list"] = true
			} else {
				seen["assert_"+emitter.ToSnakeCase(act.Output)] = true
			}
		}
	}
	imports := make([]string, 0, len(seen))
	for name := range seen {
		imports = append(imports, name)
	}
	sort.Strings(imports)
	return imports
}
